import{_ as e,o as a,c as r,ag as d}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"deno-inertia — Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"en/index.md","filePath":"en/index.md"}'),o={name:"en/index.md"};function n(i,t,s,c,l,h){return a(),r("div",null,[...t[0]||(t[0]=[d(`<h1 id="deno-inertia-—-documentation" tabindex="-1">deno-inertia — Documentation <a class="header-anchor" href="#deno-inertia-—-documentation" aria-label="Permalink to &quot;deno-inertia — Documentation&quot;">​</a></h1><p><strong><code>@streemkit/inertia-deno</code></strong> is an <a href="https://inertiajs.com" target="_blank" rel="noreferrer">Inertia.js</a> server-side adapter for Deno. It uses only standard Web APIs (<code>Request</code>, <code>Response</code>, <code>URLPattern</code>) and integrates with any compatible framework or router (Hono, Oak, std/http, etc.).</p><hr><h2 id="table-of-contents" tabindex="-1">Table of contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of contents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>Description</th></tr></thead><tbody><tr><td><a href="./installation.html">Installation</a></td><td>Prerequisites, deno.json, npm</td></tr><tr><td><a href="./quick-start.html">Quick start</a></td><td>Working project in 5 minutes</td></tr><tr><td><a href="./configuration.html">Configuration</a></td><td><code>InertiaConfig</code> — all fields</td></tr><tr><td><a href="./rendering.html">Rendering</a></td><td><code>render()</code>, <code>renderWithErrors()</code>, <code>redirect()</code></td></tr><tr><td><a href="./props.html">Props</a></td><td>normal, shared, always, lazy, defer, merge</td></tr><tr><td><a href="./forms.html">Forms &amp; validation</a></td><td>Errors, error bags, POST cycle</td></tr><tr><td><a href="./flash.html">Flash messages</a></td><td><code>__flash</code> cookie, auto-clear</td></tr><tr><td><a href="./router.html">Router</a></td><td><code>createRouter()</code>, params, middleware, groups</td></tr><tr><td><a href="./vite.html">Vite</a></td><td>Dev + production integration</td></tr><tr><td><a href="./adapters.html">Adapters</a></td><td>Hono, Oak, std/http</td></tr><tr><td><a href="./inertia-v2.html">Inertia v2</a></td><td>Deferred, merge, encryptHistory</td></tr><tr><td><a href="./typescript.html">TypeScript</a></td><td><code>PropValue&lt;T&gt;</code>, <code>PageProps&lt;T&gt;</code>, all types</td></tr><tr><td><a href="./cli.html">CLI</a></td><td><code>@streemkit/inertia-deno-cli</code> — init, dev, build, preview</td></tr></tbody></table><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><h3 id="what-is-inertia-js" tabindex="-1">What is Inertia.js? <a class="header-anchor" href="#what-is-inertia-js" aria-label="Permalink to &quot;What is Inertia.js?&quot;">​</a></h3><p>Inertia.js is a protocol that creates server-driven SPAs without REST APIs or GraphQL. The server renders pages as named components with JSON props. The client (Vue, React, Svelte) mounts these components directly — SPA navigation without manual JSON/fetch.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser ──[ GET / ]──────────────────────► Deno</span></span>
<span class="line"><span>        ◄──[ HTML + &lt;div data-page=&quot;…&quot;&gt; ]──</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Browser ──[ GET /about  X-Inertia:true ]──► Deno</span></span>
<span class="line"><span>        ◄──[ JSON { component, props, url } ]──</span></span></code></pre></div><h3 id="why-deno-inertia" tabindex="-1">Why deno-inertia? <a class="header-anchor" href="#why-deno-inertia" aria-label="Permalink to &quot;Why deno-inertia?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Constraint</th><th>Solution</th></tr></thead><tbody><tr><td>Works with Hono, Oak, std/http…</td><td>Pure <code>Request</code>/<code>Response</code> API — no framework coupling</td></tr><tr><td>Inertia v1 + v2</td><td><code>lazy</code>, <code>defer</code>, <code>merge</code>, <code>encryptHistory</code></td></tr><tr><td>Strict TypeScript</td><td><code>PropValue&lt;T&gt;</code>, <code>PageProps&lt;T&gt;</code>, generics on <code>render&lt;T&gt;()</code></td></tr><tr><td>Zero magic</td><td>Every behavior is explicit and testable</td></tr></tbody></table><h3 id="jsr-packages" tabindex="-1">JSR packages <a class="header-anchor" href="#jsr-packages" aria-label="Permalink to &quot;JSR packages&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Package</th><th>Role</th></tr></thead><tbody><tr><td><code>jsr:@streemkit/inertia-deno</code></td><td>Main server library</td></tr><tr><td><code>jsr:@streemkit/inertia-deno/hono</code></td><td>Hono adapter (<code>toWebRequest</code>)</td></tr><tr><td><code>jsr:@streemkit/inertia-deno/oak</code></td><td>Oak adapter (<code>toWebRequest</code> + <code>applyResponse</code>)</td></tr><tr><td><code>jsr:@streemkit/inertia-deno-cli</code></td><td>CLI (init, dev, build, preview)</td></tr></tbody></table>`,14)])])}const u=e(o,[["render",n]]);export{m as __pageData,u as default};
